        "import pandas as pd\n",
        "\n",
        "# 1. Tạo dữ liệu mẫu và khám phá Petri Net bằng Inductive Miner\n",
        "# (Sử dụng Inductive Miner sẽ tạo ra Petri Net \"sạch\" hơn cho việc chuyển đổi)\n",
        "event_data = {\n",
        "    'case:concept:name': ['1', '1', '1', '2', '2', '2', '3', '3', '4', '4'],\n",
