        "## Ve so do BPMN\n",
        "import pm4py\n",
        "import pandas as pd\n",
        "\n",
        "# 1. Khởi tạo dữ liệu (Dựa trên kịch bản Building Inspection đã tạo ở trên)\n",
        "event_data = {\n",
