        "## Chương trình Python Dotted Chart Analysis\n",
        "import pandas as pd\n",
        "import matplotlib.pyplot as plt\n",
        "\n",
        "# Load event log\n",
        "log = pd.read_csv(\"/content/sample_data/event_log.csv\")\n",
        "\n",
        "# Convert timestamp\n",
        "log[\"timestamp\"] = pd.to_datetime(log[\"timestamp\"])\n",
        "\n",
        "# Sort events\n",
        "log = log.sort_values(\"timestamp\")\n",
        "\n",
        "# Map case_id to numeric values\n",
        "log[\"case_num\"] = log[\"case_id\"].astype(\"category\").cat.codes\n",
        "\n",
        "# Plot dotted chart\n",
        "plt.figure(figsize=(10,6))\n",
        "\n",
        "plt.scatter(\n",
        "    log[\"timestamp\"],\n",
        "    log[\"case_num\"],\n",
        "    c=log[\"case_num\"],\n",
        "    cmap=\"tab10\",\n",
        "    alpha=0.8\n",
        ")\n",
        "\n",
        "plt.xlabel(\"Time\")\n",
        "plt.ylabel(\"Case ID\")\n",
        "plt.title(\"Dotted Chart Analysis (Process Mining)\")\n",
        "\n",
        "plt.grid(True)\n",
        "plt.show()"
